class BankingTransactionServiceImpl implements BankingTransactionService {
    @Override
    public TransactionResponse processTransaction(TransactionRequest request) throws BankingSecurityException {
        if (request == null) {
            throw new BankingSecurityException("Invalid request");
        }
        if (request.getTransactionId() == null || request.getTransactionId().trim().isEmpty()) {
            request.setTransactionId(UUID.randomUUID().toString());
        }
        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new BankingSecurityException("Invalid transaction amount");
        }
        String confirmationId = "CONF-" + UUID.randomUUID().toString().replace("-", "").substring(0, 12).toUpperCase();
        return new TransactionResponse(
                request.getTransactionId(),
                "APPROVED",
                "Transaction processed successfully",
                confirmationId
        );
    }
}

